#include<bits/stdc++.h>
using namespace std;
int main(){
    string a;
    cin>>a;
    if(a[0]!='M'||a[1]!='D'||a[2]!='A') cout<<"1 1 1 1 1";
    else{
        int x;
        for(int i=7;i>=3;i--){
            if(a[i]>='0'&&a[i]<='9'){
                x=a[i]-'0';
                break;
            }
        }
        if(x!=1&&x!=9) cout<<"0 ";
        else cout<<"1 ";
        if(x!=2&&x!=8) cout<<"0 ";
        else cout<<"1 ";
        if(x!=3&&x!=7) cout<<"0 ";
        else cout<<"1 ";
        if(x!=4&&x!=6) cout<<"0 ";
        else cout<<"1 ";
        if(x!=5&&x!=0) cout<<"0";
        else cout<<"1";
    }
}
